use strict;
my @files = sort glob("/app/papers/*.md");
foreach my $f (@files) {
    my $fname = $f; $fname =~ s|.*/||;
    print "=" x 80 . "\n";
    print "FILE: $fname\n";
    print "=" x 80 . "\n";
    open(my $fh, "<", $f) or die "Cannot open $f: $!";
    while (<$fh>) { print; }
    close($fh);
    print "\n";
}
' 2>&1 | wc -c

